import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum LogType {
  FEED = 'FEED',
  DIAPER = 'DIAPER',
  SLEEP = 'SLEEP',
  HEALTH = 'HEALTH'
}

export enum FeedType {
  BREAST = 'Breast Milk',
  FORMULA = 'Formula',
  SOLIDS = 'Solids'
}

export enum DiaperType {
  WET = 'Wet',
  DIRTY = 'Dirty',
  BOTH = 'Both'
}

export interface BaseLog {
  id: string;
  timestamp: string; // ISO String
  type: LogType;
  notes?: string;
}

export interface FeedLog extends BaseLog {
  type: LogType.FEED;
  amountMl: number;
  feedType: FeedType;
}

export interface DiaperLog extends BaseLog {
  type: LogType.DIAPER;
  status: DiaperType;
}

export interface SleepLog extends BaseLog {
  type: LogType.SLEEP;
  durationMinutes: number;
}

export interface HealthLog extends BaseLog {
  type: LogType.HEALTH;
  weightKg?: number;
  heightCm?: number;
  headCircumferenceCm?: number;
}

export type BabyLog = FeedLog | DiaperLog | SleepLog | HealthLog;

export interface DailySummary {
  date: string;
  totalMilk: number;
  totalSleep: number;
  diaperCount: number;
}

export const BABY_NAME = "Jacob";
export const BIRTH_DATE = "2025-12-19";

export const APP_COLORS = {
  primary: "blue-500",
  secondary: "indigo-500",
  accent: "amber-400",
  bg: "slate-50",
};

import { BabyLog } from '../types';

const STORAGE_KEY = 'jacob_tracker_logs';

export const getLogs = (): BabyLog[] => {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    return stored ? JSON.parse(stored) : [];
  } catch (e) {
    console.error("Failed to load logs", e);
    return [];
  }
};

export const saveLogs = (logs: BabyLog[]) => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(logs));
  } catch (e) {
    console.error("Failed to save logs", e);
  }
};

export const clearLogs = () => {
  localStorage.removeItem(STORAGE_KEY);
};

import { GoogleGenAI } from "@google/genai";
import { BabyLog, LogType } from "../types";
import { BIRTH_DATE, BABY_NAME } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateBabyInsights = async (logs: BabyLog[]): Promise<string> => {
  // Filter for last 7 days to keep context relevant and small
  const sevenDaysAgo = new Date();
  sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

  const recentLogs = logs.filter(log => new Date(log.timestamp) > sevenDaysAgo);

  const prompt = `
    You are a helpful, expert pediatric nurse assistant.
    The baby's name is ${BABY_NAME}, born on ${BIRTH_DATE}.

    Here is a JSON summary of the logs from the last 7 days:
    ${JSON.stringify(recentLogs.map(l => ({
      type: l.type,
      time: l.timestamp,
      details: l.type === LogType.FEED ? `${(l as any).amountMl}ml` : 
               l.type === LogType.HEALTH ? `Wt:${(l as any).weightKg}kg` : 
               l.type === LogType.SLEEP ? `${(l as any).durationMinutes}min` : 
               (l as any).status
    })))}

    Please provide a brief, encouraging summary (max 3 bullet points) focusing on:
    1. Feeding patterns (total intake trends).
    2. Sleep consistency.
    3. Any positive growth indicators or reminders for the parents.

    Keep the tone warm and reassuring.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "No insights available at the moment.";
  } catch (error) {
    console.error("Error generating insights:", error);
    return "Sorry, I couldn't generate insights right now. Please check your connection.";
  }
};

import React, { useMemo } from 'react';
import { BabyLog, LogType, FeedLog, SleepLog } from '../types';
import { Milk, Moon, Baby, Clock } from 'lucide-react';

interface DashboardProps {
  logs: BabyLog[];
}

export const Dashboard: React.FC<DashboardProps> = ({ logs }) => {
  const today = new Date().toDateString();

  const stats = useMemo(() => {
    const todaysLogs = logs.filter(l => new Date(l.timestamp).toDateString() === today);

    const totalMilk = todaysLogs
      .filter(l => l.type === LogType.FEED)
      .reduce((sum, l) => sum + ((l as FeedLog).amountMl || 0), 0);

    const totalSleepMinutes = todaysLogs
      .filter(l => l.type === LogType.SLEEP)
      .reduce((sum, l) => sum + ((l as SleepLog).durationMinutes || 0), 0);

    const diaperCount = todaysLogs.filter(l => l.type === LogType.DIAPER).length;

    // Last feed calculation
    const feeds = logs.filter(l => l.type === LogType.FEED).sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
    const lastFeed = feeds.length > 0 ? feeds[0] : null;

    let timeSinceFeed = "N/A";
    if (lastFeed) {
      const diffMs = new Date().getTime() - new Date(lastFeed.timestamp).getTime();
      const diffHrs = Math.floor(diffMs / (1000 * 60 * 60));
      const diffMins = Math.floor((diffMs % (1000 * 60 * 60)) / (1000 * 60));
      timeSinceFeed = `${diffHrs}h ${diffMins}m`;
    }

    return { totalMilk, totalSleepMinutes, diaperCount, timeSinceFeed };
  }, [logs, today]);

  return (
    <div className="space-y-4">
      <div className="grid grid-cols-2 gap-4">
        <div className="bg-blue-100 p-4 rounded-2xl flex flex-col items-center justify-center shadow-sm">
          <Milk className="w-8 h-8 text-blue-500 mb-2" />
          <span className="text-xs text-blue-400 font-bold uppercase tracking-wider">Today's Milk</span>
          <span className="text-2xl font-extrabold text-blue-700">{stats.totalMilk} ml</span>
        </div>

        <div className="bg-indigo-100 p-4 rounded-2xl flex flex-col items-center justify-center shadow-sm">
          <Moon className="w-8 h-8 text-indigo-500 mb-2" />
          <span className="text-xs text-indigo-400 font-bold uppercase tracking-wider">Today's Sleep</span>
          <span className="text-2xl font-extrabold text-indigo-700">
            {Math.floor(stats.totalSleepMinutes / 60)}h {stats.totalSleepMinutes % 60}m
          </span>
        </div>

        <div className="bg-amber-100 p-4 rounded-2xl flex flex-col items-center justify-center shadow-sm">
          <Baby className="w-8 h-8 text-amber-500 mb-2" />
          <span className="text-xs text-amber-400 font-bold uppercase tracking-wider">Diapers</span>
          <span className="text-2xl font-extrabold text-amber-700">{stats.diaperCount}</span>
        </div>

        <div className="bg-emerald-100 p-4 rounded-2xl flex flex-col items-center justify-center shadow-sm">
          <Clock className="w-8 h-8 text-emerald-500 mb-2" />
          <span className="text-xs text-emerald-400 font-bold uppercase tracking-wider">Last Feed</span>
          <span className="text-xl font-extrabold text-emerald-700">{stats.timeSinceFeed}</span>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { LogType, FeedType, DiaperType, BabyLog } from '../types';
import { PlusCircle } from 'lucide-react';

interface LogFormProps {
  onAddLog: (log: BabyLog) => void;
}

export const LogForm: React.FC<LogFormProps> = ({ onAddLog }) => {
  const [activeType, setActiveType] = useState<LogType>(LogType.FEED);

  // Form States
  const [amount, setAmount] = useState<number>(120);
  const [feedType, setFeedType] = useState<FeedType>(FeedType.FORMULA);
  const [diaperStatus, setDiaperStatus] = useState<DiaperType>(DiaperType.WET);
  const [sleepDuration, setSleepDuration] = useState<number>(60);
  const [weight, setWeight] = useState<number>(3.5);
  const [height, setHeight] = useState<number>(50);
  const [headCirc, setHeadCirc] = useState<number>(35);

  // Default to current time formatted for datetime-local input
  const toLocalISO = (date: Date) => {
    const offset = date.getTimezoneOffset() * 60000;
    return new Date(date.getTime() - offset).toISOString().slice(0, 16);
  };
  const [date, setDate] = useState<string>(toLocalISO(new Date()));

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const baseLog = {
      id: Date.now().toString(),
      timestamp: new Date(date).toISOString(),
    };

    let newLog: BabyLog;

    switch (activeType) {
      case LogType.FEED:
        newLog = { ...baseLog, type: LogType.FEED, amountMl: Number(amount), feedType } as any;
        break;
      case LogType.DIAPER:
        newLog = { ...baseLog, type: LogType.DIAPER, status: diaperStatus } as any;
        break;
      case LogType.SLEEP:
        newLog = { ...baseLog, type: LogType.SLEEP, durationMinutes: Number(sleepDuration) } as any;
        break;
      case LogType.HEALTH:
        newLog = { ...baseLog, type: LogType.HEALTH, weightKg: Number(weight), heightCm: Number(height), headCircumferenceCm: Number(headCirc) } as any;
        break;
      default:
        return;
    }

    onAddLog(newLog);
    // Reset date to now for next entry
    setDate(toLocalISO(new Date()));
  };

  const TabButton = ({ type, label }: { type: LogType, label: string }) => (
    <button
      type="button"
      onClick={() => setActiveType(type)}
      className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all duration-200 ${
        activeType === type 
        ? 'bg-blue-600 text-white shadow-md transform scale-105' 
        : 'bg-white text-gray-500 border border-gray-200 hover:bg-gray-50'
      }`}
    >
      {label}
    </button>
  );

  return (
    <div className="bg-white rounded-3xl shadow-lg p-6 mb-6">
      <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center gap-2">
        <PlusCircle className="w-6 h-6 text-blue-500" />
        New Entry
      </h2>

      <div className="flex gap-2 mb-6 overflow-x-auto no-scrollbar pb-1">
        <TabButton type={LogType.FEED} label="Feed" />
        <TabButton type={LogType.DIAPER} label="Diaper" />
        <TabButton type={LogType.SLEEP} label="Sleep" />
        <TabButton type={LogType.HEALTH} label="Health" />
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Time</label>
          <input
            type="datetime-local"
            value={date}
            onChange={(e) => setDate(e.target.value)}
            className="w-full p-3 rounded-xl bg-gray-50 border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none"
            required
          />
        </div>

        {activeType === LogType.FEED && (
          <>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Type</label>
              <div className="flex gap-2">
                {(Object.values(FeedType) as FeedType[]).map((t) => (
                  <button
                    key={t}
                    type="button"
                    onClick={() => setFeedType(t)}
                    className={`flex-1 py-2 rounded-lg text-xs font-semibold transition-colors ${feedType === t ? 'bg-blue-100 text-blue-700 border-2 border-blue-500' : 'bg-gray-50 border border-gray-200 text-gray-600'}`}
                  >
                    {t}
                  </button>
                ))}
              </div>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Amount (ml)</label>
              <input
                type="number"
                value={amount}
                onChange={(e) => setAmount(Number(e.target.value))}
                className="w-full p-3 rounded-xl bg-gray-50 border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="120"
              />
            </div>
          </>
        )}

        {activeType === LogType.DIAPER && (
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
            <div className="flex gap-2">
              {(Object.values(DiaperType) as DiaperType[]).map((t) => (
                <button
                  key={t}
                  type="button"
                  onClick={() => setDiaperStatus(t)}
                  className={`flex-1 py-2 rounded-lg text-xs font-semibold transition-colors ${diaperStatus === t ? 'bg-amber-100 text-amber-700 border-2 border-amber-500' : 'bg-gray-50 border border-gray-200 text-gray-600'}`}
                >
                  {t}
                </button>
              ))}
            </div>
          </div>
        )}

        {activeType === LogType.SLEEP && (
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Duration (minutes)</label>
            <input
              type="number"
              value={sleepDuration}
              onChange={(e) => setSleepDuration(Number(e.target.value))}
              className="w-full p-3 rounded-xl bg-gray-50 border border-gray-200 focus:ring-2 focus:ring-indigo-500 outline-none"
            />
          </div>
        )}

        {activeType === LogType.HEALTH && (
          <div className="grid grid-cols-3 gap-4">
            <div>
              <label className="block text-xs font-medium text-gray-700 mb-1">Weight (kg)</label>
              <input
                type="number"
                step="0.01"
                value={weight}
                onChange={(e) => setWeight(Number(e.target.value))}
                className="w-full p-2 rounded-xl bg-gray-50 border border-gray-200 focus:ring-2 focus:ring-emerald-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-xs font-medium text-gray-700 mb-1">Height (cm)</label>
              <input
                type="number"
                step="0.1"
                value={height}
                onChange={(e) => setHeight(Number(e.target.value))}
                className="w-full p-2 rounded-xl bg-gray-50 border border-gray-200 focus:ring-2 focus:ring-emerald-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-xs font-medium text-gray-700 mb-1">Head (cm)</label>
              <input
                type="number"
                step="0.1"
                value={headCirc}
                onChange={(e) => setHeadCirc(Number(e.target.value))}
                className="w-full p-2 rounded-xl bg-gray-50 border border-gray-200 focus:ring-2 focus:ring-emerald-500 outline-none"
              />
            </div>
          </div>
        )}

        <button
          type="submit"
          className="w-full mt-4 py-3 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-xl shadow-md transition-colors flex items-center justify-center gap-2"
        >
          Save Entry
        </button>
      </form>
    </div>
  );
};

import React from 'react';
import { BabyLog, LogType, FeedLog, DiaperLog, SleepLog, HealthLog } from '../types';
import { Milk, Baby, Moon, Activity, Trash2 } from 'lucide-react';

interface LogListProps {
  logs: BabyLog[];
  onDeleteLog: (id: string) => void;
}

export const LogList: React.FC<LogListProps> = ({ logs, onDeleteLog }) => {
  // Sort by date desc
  const sortedLogs = [...logs].sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

  const getIcon = (type: LogType) => {
    switch (type) {
      case LogType.FEED: return <Milk className="w-5 h-5 text-blue-500" />;
      case LogType.DIAPER: return <Baby className="w-5 h-5 text-amber-500" />;
      case LogType.SLEEP: return <Moon className="w-5 h-5 text-indigo-500" />;
      case LogType.HEALTH: return <Activity className="w-5 h-5 text-emerald-500" />;
    }
  };

  const getDetails = (log: BabyLog) => {
    switch (log.type) {
      case LogType.FEED:
        const f = log as FeedLog;
        return `${f.amountMl}ml - ${f.feedType}`;
      case LogType.DIAPER:
        return (log as DiaperLog).status;
      case LogType.SLEEP:
        const hours = Math.floor((log as SleepLog).durationMinutes / 60);
        const mins = (log as SleepLog).durationMinutes % 60;
        return `${hours > 0 ? `${hours}h ` : ''}${mins}m`;
      case LogType.HEALTH:
        const h = log as HealthLog;
        return [
           h.weightKg ? `${h.weightKg}kg` : '',
           h.heightCm ? `${h.heightCm}cm` : ''
        ].filter(Boolean).join(', ');
      default: return '';
    }
  };

  return (
    <div className="space-y-3">
      {sortedLogs.map((log) => (
        <div key={log.id} className="bg-white p-4 rounded-xl shadow-sm flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className={`p-2 rounded-full bg-gray-50`}>
              {getIcon(log.type)}
            </div>
            <div>
              <p className="font-bold text-gray-800 text-sm">
                {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                 <span className="text-gray-400 font-normal text-xs ml-2">
                   {new Date(log.timestamp).toLocaleDateString()}
                 </span>
              </p>
              <p className="text-gray-600 text-sm">{getDetails(log)}</p>
            </div>
          </div>
          <button 
            onClick={() => onDeleteLog(log.id)}
            className="p-2 text-gray-300 hover:text-red-400 transition-colors"
          >
            <Trash2 className="w-4 h-4" />
          </button>
        </div>
      ))}
      {sortedLogs.length === 0 && (
        <div className="text-center text-gray-400 py-8">
          No records yet. Start tracking Jacob's journey!
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BabyLog } from './types';
import { getLogs, saveLogs } from './services/storageService';
import { generateBabyInsights } from './services/geminiService';
import { Dashboard } from './components/Dashboard';
import { LogForm } from './components/LogForm';
import { LogList } from './components/LogList';
import { Sparkles, Calendar } from 'lucide-react';
import { BABY_NAME, BIRTH_DATE } from './constants';

const App: React.FC = () => {
  const [logs, setLogs] = useState<BabyLog[]>([]);
  const [insight, setInsight] = useState<string>("");
  const [loadingInsight, setLoadingInsight] = useState(false);

  useEffect(() => {
    setLogs(getLogs());
  }, []);

  useEffect(() => {
    saveLogs(logs);
  }, [logs]);

  const handleAddLog = (newLog: BabyLog) => {
    setLogs(prev => [newLog, ...prev]);
  };

  const handleDeleteLog = (id: string) => {
    if (confirm("Delete this record?")) {
      setLogs(prev => prev.filter(l => l.id !== id));
    }
  };

  const handleGetInsight = async () => {
    if (logs.length === 0) return;
    setLoadingInsight(true);
    const result = await generateBabyInsights(logs);
    setInsight(result);
    setLoadingInsight(false);
  };

  // Calculate Age
  const birth = new Date(BIRTH_DATE);
  const now = new Date();
  const diffTime = Math.abs(now.getTime() - birth.getTime());
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 

  return (
    <div className="min-h-screen pb-20 max-w-md mx-auto bg-gray-50 shadow-2xl overflow-hidden min-w-[320px]">
      {/* Header */}
      <header className="bg-white p-6 pb-8 rounded-b-[2.5rem] shadow-sm mb-6">
        <div className="flex justify-between items-start mb-4">
          <div>
            <h1 className="text-3xl font-black text-gray-800 tracking-tight">{BABY_NAME}</h1>
            <p className="text-blue-500 font-bold text-sm uppercase tracking-wide mt-1 flex items-center gap-1">
              <Calendar className="w-4 h-4" />
              {diffDays} Days Old
            </p>
          </div>
          <div className="bg-blue-50 text-blue-600 px-3 py-1 rounded-full text-xs font-bold">
            {BIRTH_DATE}
          </div>
        </div>

        <Dashboard logs={logs} />
      </header>

      <main className="px-5 space-y-6">
        {/* AI Insight Section */}
        <section>
           <div className="flex items-center justify-between mb-3">
              <h2 className="font-bold text-gray-800 text-lg flex items-center gap-2">
                <Sparkles className="w-5 h-5 text-purple-500" />
                AI Insights
              </h2>
              <button 
                onClick={handleGetInsight}
                disabled={loadingInsight || logs.length === 0}
                className="text-xs font-bold text-purple-600 bg-purple-50 px-3 py-1.5 rounded-lg hover:bg-purple-100 disabled:opacity-50"
              >
                {loadingInsight ? 'Analyzing...' : 'Refresh'}
              </button>
           </div>

           {insight && (
             <div className="bg-purple-50 p-4 rounded-2xl text-sm text-gray-700 leading-relaxed border border-purple-100 shadow-sm animate-fade-in">
               <div className="whitespace-pre-line">{insight}</div>
             </div>
           )}
           {!insight && (
             <div className="bg-white p-4 rounded-2xl text-sm text-gray-400 text-center border border-gray-100 border-dashed">
               Tap refresh to get a weekly summary of Jacob's progress.
             </div>
           )}
        </section>

        {/* Input Form */}
        <section>
          <LogForm onAddLog={handleAddLog} />
        </section>

        {/* Recent History */}
        <section>
          <h2 className="font-bold text-gray-800 text-lg mb-3">Recent History</h2>
          <LogList logs={logs} onDeleteLog={handleDeleteLog} />
        </section>
      </main>
    </div>
  );
};

export default App;

{
  "name": "Jacob 成長日記",
  "description": "Jacob 的全方位嬰兒追蹤器，記錄飲食、睡眠、換尿片及生長狀況，並具備 AI 分析功能。",
  "requestFramePermissions": []
}

export enum LogType {
  FEED = 'FEED',
  DIAPER = 'DIAPER',
  SLEEP = 'SLEEP',
  HEALTH = 'HEALTH'
}

export enum FeedType {
  BREAST = '母乳',
  FORMULA = '配方奶',
  SOLIDS = '副食品'
}

export enum DiaperType {
  WET = '小便',
  DIRTY = '大便',
  BOTH = '大小便'
}

export interface BaseLog {
  id: string;
  timestamp: string; // ISO String
  type: LogType;
  notes?: string;
}

export interface FeedLog extends BaseLog {
  type: LogType.FEED;
  amountMl: number;
  feedType: FeedType;
}

export interface DiaperLog extends BaseLog {
  type: LogType.DIAPER;
  status: DiaperType;
}

export interface SleepLog extends BaseLog {
  type: LogType.SLEEP;
  durationMinutes: number;
}

export interface HealthLog extends BaseLog {
  type: LogType.HEALTH;
  weightKg?: number;
  heightCm?: number;
  headCircumferenceCm?: number;
}

export type BabyLog = FeedLog | DiaperLog | SleepLog | HealthLog;

export interface DailySummary {
  date: string;
  totalMilk: number;
  totalSleep: number;
  diaperCount: number;
}

import { GoogleGenAI } from "@google/genai";
import { BabyLog, LogType } from "../types";
import { BIRTH_DATE, BABY_NAME } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateBabyInsights = async (logs: BabyLog[]): Promise<string> => {
  // Filter for last 7 days to keep context relevant and small
  const sevenDaysAgo = new Date();
  sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

  const recentLogs = logs.filter(log => new Date(log.timestamp) > sevenDaysAgo);

  const prompt = `
    你是一位專業、親切的兒科護理助手。
    寶寶的名字是 ${BABY_NAME}，出生於 ${BIRTH_DATE}。

