        <TabButton type={LogType.HEALTH} label="健康" />
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">時間</label>
          <input
            type="datetime-local"
