          />
        </div>

        {activeType === LogType.FEED && (
          <>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">類型</label>
              <div className="flex gap-2">
                {(Object.values(FeedType) as FeedType[]).map((t) => (
