                placeholder="120"
              />
            </div>
          </>
        )}

        {activeType === LogType.DIAPER && (
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">狀態</label>
            <div className="flex gap-2">
              {(Object.values(DiaperType) as DiaperType[]).map((t) => (
