import React from 'react';
import { BabyLog, LogType, FeedLog, DiaperLog, SleepLog, HealthLog, OtherLog } from '../types';
import { Milk, Baby, Moon, Activity, Trash2, StickyNote } from 'lucide-react';

interface LogListProps {
  logs: BabyLog[];
  onDeleteLog: (id: string) => void;
}

export const LogList: React.FC<LogListProps> = ({ logs, onDeleteLog }) => {
  // Sort by date desc
  const sortedLogs = [...logs].sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

  const getIcon = (type: LogType) => {
    switch (type) {
      case LogType.FEED: return <Milk className="w-5 h-5 text-blue-500" />;
      case LogType.DIAPER: return <Baby className="w-5 h-5 text-amber-500" />;
      case LogType.SLEEP: return <Moon className="w-5 h-5 text-indigo-500" />;
      case LogType.HEALTH: return <Activity className="w-5 h-5 text-emerald-500" />;
      case LogType.OTHER: return <StickyNote className="w-5 h-5 text-pink-500" />;
    }
  };

  const getDetails = (log: BabyLog) => {
    switch (log.type) {
      case LogType.FEED:
        const f = log as FeedLog;
        return `${f.amountMl}ml - ${f.feedType}`;
      case LogType.DIAPER:
        return (log as DiaperLog).status;
      case LogType.SLEEP:
        const hours = Math.floor((log as SleepLog).durationMinutes / 60);
        const mins = (log as SleepLog).durationMinutes % 60;
        return `${hours > 0 ? `${hours}小時 ` : ''}${mins}分鐘`;
      case LogType.HEALTH:
        const h = log as HealthLog;
        return [
           h.weightKg ? `${h.weightKg}kg` : '',
           h.heightCm ? `${h.heightCm}cm` : ''
        ].filter(Boolean).join(', ');
      case LogType.OTHER:
        return (log as OtherLog).details;
      default: return '';
    }
  };

  return (
    <div className="space-y-3">
      {sortedLogs.map((log) => (
        <div key={log.id} className="bg-white p-4 rounded-xl shadow-sm flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className={`p-2 rounded-full bg-gray-50`}>
              {getIcon(log.type)}
            </div>
            <div>
              <p className="font-bold text-gray-800 text-sm">
                {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                 <span className="text-gray-400 font-normal text-xs ml-2">
                   {new Date(log.timestamp).toLocaleDateString()}
                 </span>
              </p>
              <p className="text-gray-600 text-sm whitespace-pre-wrap">{getDetails(log)}</p>
            </div>
          </div>
          <button 
            onClick={() => onDeleteLog(log.id)}
            className="p-2 text-gray-300 hover:text-red-400 transition-colors"
          >
            <Trash2 className="w-4 h-4" />
          </button>
        </div>
      ))}
      {sortedLogs.length === 0 && (
        <div className="text-center text-gray-400 py-8">
          暫無記錄。開始記錄 Jacob 的成長歷程吧！
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { BabyLog } from './types';
import { getLogs, saveLogs, exportLogsToJSON } from './services/storageService';
import { generateBabyInsights } from './services/geminiService';
import { Dashboard } from './components/Dashboard';
import { LogForm } from './components/LogForm';
import { LogList } from './components/LogList';
import { Sparkles, Calendar, Download, Baby } from 'lucide-react';
import { BABY_NAME, BIRTH_DATE } from './constants';

const App: React.FC = () => {
  const [logs, setLogs] = useState<BabyLog[]>([]);
  const [insight, setInsight] = useState<string>("");
  const [loadingInsight, setLoadingInsight] = useState(false);

  useEffect(() => {
    setLogs(getLogs());
  }, []);

  useEffect(() => {
    saveLogs(logs);
  }, [logs]);

  const handleAddLog = (newLog: BabyLog) => {
    setLogs(prev => [newLog, ...prev]);
  };

  const handleDeleteLog = (id: string) => {
    if (confirm("確定刪除這條記錄嗎？")) {
      setLogs(prev => prev.filter(l => l.id !== id));
    }
  };

  const handleGetInsight = async () => {
    if (logs.length === 0) return;
    setLoadingInsight(true);
    const result = await generateBabyInsights(logs);
    setInsight(result);
    setLoadingInsight(false);
  };

  // Calculate Age (Inclusive of birth day, so +1)
  const birth = new Date(BIRTH_DATE);
  const now = new Date();
  // Set time to midnight for accurate day calculation
  const birthDay = new Date(birth.getFullYear(), birth.getMonth(), birth.getDate());
  const currentDay = new Date(now.getFullYear(), now.getMonth(), now.getDate());

  // Calculate difference in days and add 1 to count the birth day as Day 1
  const diffTime = currentDay.getTime() - birthDay.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1; 

  const todayStr = new Date().toLocaleDateString('zh-TW', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    weekday: 'short'
  });

  return (
    <div className="min-h-screen pb-20 max-w-md mx-auto bg-gray-50 shadow-2xl overflow-hidden min-w-[320px]">
      {/* Header */}
      <header className="bg-white px-6 pt-8 pb-8 rounded-b-[2.5rem] shadow-sm mb-6">
        <div className="flex flex-col items-center mb-6">
          <p className="text-gray-500 font-bold text-sm tracking-wide mb-1">{todayStr}</p>
          <h1 className="text-4xl font-black text-gray-800 tracking-tight mb-3">{BABY_NAME}</h1>

          <div className="flex items-center gap-2 bg-blue-50 border border-blue-100 px-4 py-1.5 rounded-full">
            <Baby className="w-4 h-4 text-blue-500" />
            <span className="text-blue-600 font-bold text-sm">
              出生第 {diffDays} 天
            </span>
          </div>
        </div>

        <Dashboard logs={logs} />
      </header>

      <main className="px-5 space-y-6">
        {/* Input Form */}
        <section>
          <LogForm onAddLog={handleAddLog} />
        </section>

        {/* AI Insight Section */}
        <section>
           <div className="flex items-center justify-between mb-3">
              <h2 className="font-bold text-gray-800 text-lg flex items-center gap-2">
                <Sparkles className="w-5 h-5 text-purple-500" />
                AI 成長分析
              </h2>
              <button 
                onClick={handleGetInsight}
                disabled={loadingInsight || logs.length === 0}
                className="text-xs font-bold text-purple-600 bg-purple-50 px-3 py-1.5 rounded-lg hover:bg-purple-100 disabled:opacity-50"
              >
                {loadingInsight ? '分析中...' : '重新分析'}
              </button>
           </div>

           {insight && (
             <div className="bg-purple-50 p-4 rounded-2xl text-sm text-gray-700 leading-relaxed border border-purple-100 shadow-sm animate-fade-in">
               <div className="whitespace-pre-line">{insight}</div>
             </div>
           )}
           {!insight && (
             <div className="bg-white p-4 rounded-2xl text-sm text-gray-400 text-center border border-gray-100 border-dashed">
               點擊分析以獲取 Jacob 的每週成長摘要。
             </div>
           )}
        </section>

        {/* Recent History */}
        <section>
          <h2 className="font-bold text-gray-800 text-lg mb-3">最近記錄</h2>
          <LogList logs={logs} onDeleteLog={handleDeleteLog} />
        </section>

        {/* Settings / Tools */}
        <section className="pt-4 border-t border-gray-200">
           <button 
             onClick={() => exportLogsToJSON(logs)}
             className="w-full py-3 flex items-center justify-center gap-2 text-gray-500 bg-white border border-gray-200 rounded-xl hover:bg-gray-50 transition-colors text-sm font-semibold"
           >
             <Download className="w-4 h-4" />
             匯出資料備份 (JSON)
           </button>
        </section>
      </main>
    </div>
  );
};

export default App;

import { GoogleGenAI } from "@google/genai";
import { BabyLog, LogType } from "../types";
import { BIRTH_DATE, BABY_NAME } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateBabyInsights = async (logs: BabyLog[]): Promise<string> => {
  // Filter for last 7 days to keep context relevant and small
  const sevenDaysAgo = new Date();
  sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

  const recentLogs = logs.filter(log => new Date(log.timestamp) > sevenDaysAgo);

  const prompt = `
    你是一位專業、親切的兒科護理助手。
    寶寶的名字是 ${BABY_NAME}，出生於 ${BIRTH_DATE}。

    這是過去 7 天的記錄摘要 (JSON 格式):
    ${JSON.stringify(recentLogs.map(l => ({
      type: l.type,
      time: l.timestamp,
      details: l.type === LogType.FEED ? `${(l as any).amountMl}ml` : 
               l.type === LogType.HEALTH ? `重:${(l as any).weightKg}kg` : 
               l.type === LogType.SLEEP ? `${(l as any).durationMinutes}分` : 
               l.type === LogType.OTHER ? `${(l as any).details}` :
               (l as any).status
    })))}

    請提供一份簡短且令人安心的繁體中文摘要 (最多 3 點)，重點關注：
    1. 飲食模式 (總攝取量趨勢)。
    2. 睡眠規律性。
    3. 任何正向的成長指標、健康狀況或其他值得注意的事件。

    語氣請保持溫暖和鼓勵。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "目前無法產生分析報告。";
  } catch (error) {
    console.error("Error generating insights:", error);
    return "抱歉，目前無法產生分析。請檢查您的網路連線。";
  }
};

