import React from 'react';
import { BabyLog, LogType, FeedLog, DiaperLog, SleepLog, HealthLog, OtherLog } from '../types';
import { Milk, Baby, Moon, Activity, Trash2, StickyNote } from 'lucide-react';

interface LogListProps {
  logs: BabyLog[];
  onDeleteLog: (id: string) => void;
}

export const LogList: React.FC<LogListProps> = ({ logs, onDeleteLog }) => {
  // Sort by date desc
  const sortedLogs = [...logs].sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

  const getIcon = (type: LogType) => {
    switch (type) {
      case LogType.FEED: return <Milk className="w-5 h-5 text-blue-500" />;
      case LogType.DIAPER: return <Baby className="w-5 h-5 text-amber-500" />;
      case LogType.SLEEP: return <Moon className="w-5 h-5 text-indigo-500" />;
      case LogType.HEALTH: return <Activity className="w-5 h-5 text-emerald-500" />;
      case LogType.OTHER: return <StickyNote className="w-5 h-5 text-pink-500" />;
    }
  };

  const getDetails = (log: BabyLog) => {
    switch (log.type) {
      case LogType.FEED:
        const f = log as FeedLog;
        return `${f.amountMl}ml - ${f.feedType}`;
      case LogType.DIAPER:
        return (log as DiaperLog).status;
      case LogType.SLEEP:
        // Calculate start time based on end time (timestamp) and duration
        const durationMins = (log as SleepLog).durationMinutes;
        const endTime = new Date(log.timestamp);
        const startTime = new Date(endTime.getTime() - durationMins * 60000);

        const formatTime = (d: Date) => d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

        const hours = Math.floor(durationMins / 60);
        const mins = durationMins % 60;
        const durationStr = `${hours > 0 ? `${hours}小時 ` : ''}${mins}分鐘`;

        return `${formatTime(startTime)} - ${formatTime(endTime)}\n(${durationStr})`;
      case LogType.HEALTH:
        const h = log as HealthLog;
        return [
           h.weightKg ? `${h.weightKg}kg` : '',
           h.heightCm ? `${h.heightCm}cm` : ''
        ].filter(Boolean).join(', ');
      case LogType.OTHER:
        return (log as OtherLog).details;
      default: return '';
    }
  };

  return (
    <div className="space-y-3">
      {sortedLogs.map((log) => (
        <div key={log.id} className="bg-white p-4 rounded-xl shadow-sm flex items-center justify-between animate-fade-in">
          <div className="flex items-center gap-3">
            <div className={`p-2 rounded-full bg-gray-50`}>
              {getIcon(log.type)}
            </div>
            <div>
              <p className="font-bold text-gray-800 text-sm">
                {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                 <span className="text-gray-400 font-normal text-xs ml-2">
                   {new Date(log.timestamp).toLocaleDateString()}
                 </span>
              </p>
              <p className="text-gray-600 text-sm whitespace-pre-wrap leading-tight mt-1">{getDetails(log)}</p>
            </div>
          </div>
          <button 
            onClick={() => onDeleteLog(log.id)}
            className="p-2 text-gray-300 hover:text-red-400 transition-colors"
          >
            <Trash2 className="w-4 h-4" />
          </button>
        </div>
      ))}
      {sortedLogs.length === 0 && (
        <div className="text-center text-gray-400 py-8 bg-white rounded-xl border border-dashed border-gray-200">
          <p className="text-sm">這一天沒有記錄。</p>
        </div>
      )}
    </div>
  );
};

import { db } from './firebase';
import { 
  collection, 
  setDoc, 
  deleteDoc, 
  doc, 
  onSnapshot, 
  query, 
  orderBy 
} from "firebase/firestore";
import { BabyLog } from '../types';

const COLLECTION_NAME = 'jacob_logs';
const STATUS_DOC_ID = 'status_sleep'; // Special document to track active sleep

// 監聽資料庫變更 (即時同步)
export const subscribeToLogs = (onUpdate: (logs: BabyLog[]) => void) => {
  // Filter out the status document from the main log list
  const q = query(collection(db, COLLECTION_NAME), orderBy("timestamp", "desc"));

  const unsubscribe = onSnapshot(q, (snapshot) => {
    const logs: BabyLog[] = [];
    snapshot.forEach((doc) => {
      // Skip special status documents
      if (doc.id !== STATUS_DOC_ID) {
        logs.push(doc.data() as BabyLog);
      }
    });
    onUpdate(logs);
  }, (error) => {
    console.error("Firebase sync error:", error);
  });

  return unsubscribe;
};

// 監聽睡眠狀態
export const subscribeToSleepStatus = (onUpdate: (startTime: string | null) => void) => {
  const unsubscribe = onSnapshot(doc(db, COLLECTION_NAME, STATUS_DOC_ID), (doc) => {
    if (doc.exists() && doc.data().startTime) {
      onUpdate(doc.data().startTime);
    } else {
      onUpdate(null);
    }
  });
  return unsubscribe;
};

// 設定開始睡眠
export const setSleepStatus = async (startTime: string) => {
  try {
    await setDoc(doc(db, COLLECTION_NAME, STATUS_DOC_ID), { startTime });
  } catch (e) {
    console.error("Error setting sleep status:", e);
  }
};

// 清除睡眠狀態 (起床)
export const clearSleepStatus = async () => {
  try {
    await deleteDoc(doc(db, COLLECTION_NAME, STATUS_DOC_ID));
  } catch (e) {
    console.error("Error clearing sleep status:", e);
  }
};

// 新增記錄 (上傳雲端)
export const addLogToCloud = async (log: BabyLog) => {
  try {
    // 使用 log.id 作為文件的 ID，避免重複
    await setDoc(doc(db, COLLECTION_NAME, log.id), log);
  } catch (e) {
    console.error("Error adding document: ", e);
    alert("儲存失敗，請檢查網路連線");
  }
};

// 刪除記錄 (雲端刪除)
export const deleteLogFromCloud = async (id: string) => {
  try {
    await deleteDoc(doc(db, COLLECTION_NAME, id));
  } catch (e) {
    console.error("Error removing document: ", e);
    alert("刪除失敗，請檢查網路連線");
  }
};

// 匯出備份 (保留功能)
export const exportLogsToJSON = (logs: BabyLog[]) => {
  const dataStr = JSON.stringify(logs, null, 2);
  const blob = new Blob([dataStr], { type: "application/json" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = `jacob_logs_${new Date().toISOString().split('T')[0]}.json`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
};

