           </ol>

           <div className="text-center text-xs text-gray-400">
             完成後，請重新整理此頁面。
           </div>
        </div>
      </div>
    );
  }

  // Helper: Get Local ISO Date string (YYYY-MM-DD)
  const getLocalDateString = (date: Date) => {
    const offset = date.getTimezoneOffset() * 60000;
    return new Date(date.getTime() - offset).toISOString().split('T')[0];
  };

  const [logs, setLogs] = useState<BabyLog[]>([]);
  const [sleepStartTime, setSleepStartTime] = useState<string | null>(null);
  const [insight, setInsight] = useState<string>("");
  const [loadingInsight, setLoadingInsight] = useState(false);
  const [selectedDate, setSelectedDate] = useState<string>(getLocalDateString(new Date()));

  // 啟動時訂閱雲端資料
  useEffect(() => {
    const unsubscribeLogs = subscribeToLogs((updatedLogs) => {
      setLogs(updatedLogs);
    });
    const unsubscribeSleep = subscribeToSleepStatus((startTime) => {
      setSleepStartTime(startTime);
    });
    return () => {
      unsubscribeLogs();
      unsubscribeSleep();
    };
  }, []);

  // 新增時直接傳到雲端
  const handleAddLog = (newLog: BabyLog) => {
    addLogToCloud(newLog);
    // 如果新增的日期不是當前選擇的日期，自動切換到新增的那一天 (UX 優化)
    const logDate = getLocalDateString(new Date(newLog.timestamp));
    if (logDate !== selectedDate) {
      setSelectedDate(logDate);
    }
  };

  // 處理睡眠狀態變更
  const handleSleepStart = (startTime: string) => {
    setSleepStatus(startTime);
  };

  const handleSleepEnd = (log: BabyLog) => {
    addLogToCloud(log);
    clearSleepStatus();
    // 自動切換到記錄日期
    const logDate = getLocalDateString(new Date(log.timestamp));
    if (logDate !== selectedDate) {
      setSelectedDate(logDate);
    }
  };

  // 刪除時直接通知雲端
  const handleDeleteLog = (id: string) => {
    if (confirm("確定刪除這條記錄嗎？")) {
      deleteLogFromCloud(id);
    }
  };

  const handleGetInsight = async () => {
    if (logs.length === 0) return;
    setLoadingInsight(true);
    const result = await generateBabyInsights(logs);
    setInsight(result);
    setLoadingInsight(false);
  };

  // Change Date Helper
  const changeDate = (days: number) => {
    const date = new Date(selectedDate);
    date.setDate(date.getDate() + days);
    setSelectedDate(getLocalDateString(date));
  };

  // Filter logs based on selected date
  const filteredLogs = useMemo(() => {
    return logs.filter(log => {
      const logDateStr = getLocalDateString(new Date(log.timestamp));
      return logDateStr === selectedDate;
    });
  }, [logs, selectedDate]);

  // Calculate stats for the selected date
  const dailyStats = useMemo(() => {
    const totalMilk = filteredLogs
      .filter(l => l.type === LogType.FEED)
      .reduce((sum, l) => sum + ((l as FeedLog).amountMl || 0), 0);

    const totalSleepMinutes = filteredLogs
      .filter(l => l.type === LogType.SLEEP)
      .reduce((sum, l) => sum + ((l as SleepLog).durationMinutes || 0), 0);

    const diaperCount = filteredLogs.filter(l => l.type === LogType.DIAPER).length;

    return { totalMilk, totalSleepMinutes, diaperCount };
  }, [filteredLogs]);

  // Calculate Age
  const birth = new Date(BIRTH_DATE);
  const now = new Date();
  const birthDay = new Date(birth.getFullYear(), birth.getMonth(), birth.getDate());
  const currentDay = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const diffTime = currentDay.getTime() - birthDay.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1; 

  const todayStr = new Date().toLocaleDateString('zh-TW', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    weekday: 'short'
  });

  return (
    <div className="min-h-screen pb-20 max-w-md mx-auto bg-gray-50 shadow-2xl overflow-hidden min-w-[320px]">
      {/* Header */}
      <header className="bg-white px-6 pt-8 pb-8 rounded-b-[2.5rem] shadow-sm mb-6">
        <div className="flex flex-col items-center mb-6">
          <p className="text-gray-500 font-bold text-sm tracking-wide mb-1">{todayStr}</p>
          <h1 className="text-4xl font-black text-gray-800 tracking-tight mb-3">{BABY_NAME}</h1>

          <div className="flex items-center gap-2 bg-blue-50 border border-blue-100 px-4 py-1.5 rounded-full">
            <Baby className="w-4 h-4 text-blue-500" />
            <span className="text-blue-600 font-bold text-sm">
              出生第 {diffDays} 天
            </span>
          </div>
          <div className="mt-2 flex items-center gap-1 text-xs text-green-600 bg-green-50 px-2 py-0.5 rounded-full">
             <CloudLightning className="w-3 h-3" />
             <span>雲端同步中</span>
          </div>
        </div>

        {/* Main Dashboard (Always shows TODAY's snapshot) */}
        <Dashboard 
          logs={logs} 
          isSleeping={!!sleepStartTime} 
          sleepStartTime={sleepStartTime}
        />
      </header>

      <main className="px-5 space-y-8">
        {/* Input Form */}
        <section>
          <LogForm 
            onAddLog={handleAddLog} 
            isSleeping={!!sleepStartTime}
            sleepStartTime={sleepStartTime}
            onStartSleep={handleSleepStart}
            onEndSleep={handleSleepEnd}
          />
        </section>

        {/* AI Insight Section */}
        <section>
           <div className="flex items-center justify-between mb-3">
              <h2 className="font-bold text-gray-800 text-lg flex items-center gap-2">
                <Sparkles className="w-5 h-5 text-purple-500" />
                AI 成長分析
              </h2>
              <button 
                onClick={handleGetInsight}
                disabled={loadingInsight || logs.length === 0}
                className="text-xs font-bold text-purple-600 bg-purple-50 px-3 py-1.5 rounded-lg hover:bg-purple-100 disabled:opacity-50"
              >
                {loadingInsight ? '分析中...' : '重新分析'}
              </button>
           </div>

           {insight && (
             <div className="bg-purple-50 p-4 rounded-2xl text-sm text-gray-700 leading-relaxed border border-purple-100 shadow-sm animate-fade-in">
               <div className="whitespace-pre-line">{insight}</div>
             </div>
           )}
           {!insight && (
             <div className="bg-white p-4 rounded-2xl text-sm text-gray-400 text-center border border-gray-100 border-dashed">
               點擊分析以獲取 Jacob 的每週成長摘要。
             </div>
           )}
        </section>

        {/* History & Logs Section */}
        <section>
          <div className="flex items-center justify-between mb-4">
             <h2 className="font-bold text-gray-800 text-lg flex items-center gap-2">
               <Calendar className="w-5 h-5 text-gray-600" />
               歷史記錄
             </h2>
          </div>

          {/* Date Picker Control */}
          <div className="bg-white p-2 rounded-2xl shadow-sm border border-gray-100 mb-4 flex items-center justify-between">
            <button onClick={() => changeDate(-1)} className="p-2 hover:bg-gray-100 rounded-xl text-gray-500">
              <ChevronLeft className="w-5 h-5" />
            </button>
            <div className="relative">
              <input 
                type="date" 
                value={selectedDate}
                onChange={(e) => setSelectedDate(e.target.value)}
                className="font-bold text-gray-700 bg-transparent border-none focus:ring-0 text-center text-lg outline-none cursor-pointer"
              />
            </div>
            <button onClick={() => changeDate(1)} className="p-2 hover:bg-gray-100 rounded-xl text-gray-500" disabled={selectedDate >= getLocalDateString(new Date())}>
              <ChevronRight className="w-5 h-5" />
            </button>
          </div>

          {/* Daily Mini Stats */}
          <div className="grid grid-cols-3 gap-2 mb-4">
             <div className="bg-blue-50 rounded-xl p-2 flex flex-col items-center justify-center border border-blue-100">
                <div className="flex items-center gap-1 mb-1">
                   <Milk className="w-3 h-3 text-blue-400" />
                   <span className="text-[10px] text-blue-400 font-bold uppercase">奶量</span>
                </div>
                <span className="text-sm font-black text-blue-700">{dailyStats.totalMilk} ml</span>
             </div>
             <div className="bg-indigo-50 rounded-xl p-2 flex flex-col items-center justify-center border border-indigo-100">
                <div className="flex items-center gap-1 mb-1">
                   <Moon className="w-3 h-3 text-indigo-400" />
                   <span className="text-[10px] text-indigo-400 font-bold uppercase">睡眠</span>
                </div>
                <span className="text-sm font-black text-indigo-700">
                   {Math.floor(dailyStats.totalSleepMinutes / 60)}h {dailyStats.totalSleepMinutes % 60}m
                </span>
             </div>
             <div className="bg-amber-50 rounded-xl p-2 flex flex-col items-center justify-center border border-amber-100">
                <div className="flex items-center gap-1 mb-1">
                   <Layers className="w-3 h-3 text-amber-400" />
                   <span className="text-[10px] text-amber-400 font-bold uppercase">換片</span>
                </div>
                <span className="text-sm font-black text-amber-700">{dailyStats.diaperCount}</span>
             </div>
          </div>

          <LogList logs={filteredLogs} onDeleteLog={handleDeleteLog} />
        </section>

        {/* Trends Chart Section (NEW) */}
        <section>
          <TrendsChart logs={logs} />
        </section>

        {/* Settings / Tools */}
        <section className="pt-4 border-t border-gray-200">
           <div className="grid grid-cols-1 gap-3">
             <button 
               onClick={() => exportLogsToJSON(logs)}
               className="py-3 flex items-center justify-center gap-2 text-gray-500 bg-white border border-gray-200 rounded-xl hover:bg-gray-50 transition-colors text-sm font-semibold"
             >
               <Download className="w-4 h-4" />
               匯出備份 (JSON)
             </button>
           </div>
           <p className="text-center text-xs text-gray-400 mt-2">
             * 資料已啟用即時雲端同步
           </p>
        </section>
      </main>
    </div>
  );
};

export default App;

import React, { useMemo, useState, useEffect } from 'react';
import { BabyLog, LogType, FeedLog, SleepLog } from '../types';
import { Milk, Moon, Baby, Clock, Zap } from 'lucide-react';

interface DashboardProps {
  logs: BabyLog[];
  isSleeping: boolean;
  sleepStartTime: string | null;
}

export const Dashboard: React.FC<DashboardProps> = ({ logs, isSleeping, sleepStartTime }) => {
  const today = new Date().toDateString();
  const [elapsed, setElapsed] = useState<string>("0h 0m");

  // Timer for active sleep
  useEffect(() => {
    if (!isSleeping || !sleepStartTime) return;

    const interval = setInterval(() => {
        const start = new Date(sleepStartTime).getTime();
        const now = new Date().getTime();
        const diffMs = now - start;
        const hrs = Math.floor(diffMs / (1000 * 60 * 60));
        const mins = Math.floor((diffMs % (1000 * 60 * 60)) / (1000 * 60));
        setElapsed(`${hrs}小時 ${mins}分`);
    }, 60000); // Update every minute

    // Initial set
    const start = new Date(sleepStartTime).getTime();
    const now = new Date().getTime();
    const diffMs = now - start;
    const hrs = Math.floor(diffMs / (1000 * 60 * 60));
    const mins = Math.floor((diffMs % (1000 * 60 * 60)) / (1000 * 60));
    setElapsed(`${hrs}小時 ${mins}分`);

    return () => clearInterval(interval);
  }, [isSleeping, sleepStartTime]);

  const stats = useMemo(() => {
    const todaysLogs = logs.filter(l => new Date(l.timestamp).toDateString() === today);

    const totalMilk = todaysLogs
      .filter(l => l.type === LogType.FEED)
      .reduce((sum, l) => sum + ((l as FeedLog).amountMl || 0), 0);

    const totalSleepMinutes = todaysLogs
      .filter(l => l.type === LogType.SLEEP)
      .reduce((sum, l) => sum + ((l as SleepLog).durationMinutes || 0), 0);

    const diaperCount = todaysLogs.filter(l => l.type === LogType.DIAPER).length;

    // Last feed calculation
    const feeds = logs.filter(l => l.type === LogType.FEED).sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
    const lastFeed = feeds.length > 0 ? feeds[0] : null;

    let timeSinceFeed = "無";
    if (lastFeed) {
      const diffMs = new Date().getTime() - new Date(lastFeed.timestamp).getTime();
      const diffHrs = Math.floor(diffMs / (1000 * 60 * 60));
      const diffMins = Math.floor((diffMs % (1000 * 60 * 60)) / (1000 * 60));
      timeSinceFeed = `${diffHrs}小時 ${diffMins}分`;
    }

    return { totalMilk, totalSleepMinutes, diaperCount, timeSinceFeed };
  }, [logs, today]);

  return (
    <div className="space-y-4">
      {isSleeping && (
        <div className="bg-indigo-600 rounded-2xl p-5 text-white shadow-lg relative overflow-hidden animate-pulse-slow">
            <div className="absolute right-[-20px] top-[-20px] opacity-20">
                <Moon className="w-32 h-32" />
            </div>
            <div className="relative z-10 flex flex-col items-center">
                <div className="flex items-center gap-2 mb-2">
                    <span className="w-2 h-2 bg-green-400 rounded-full animate-ping"></span>
                    <span className="text-sm font-bold text-indigo-200 uppercase tracking-widest">目前正在睡覺</span>
                </div>
                <div className="text-4xl font-black mb-1 font-mono tracking-tight">
                    {elapsed}
                </div>
                <div className="text-indigo-200 text-xs">
                    入睡時間: {new Date(sleepStartTime!).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                </div>
            </div>
        </div>
      )}

      <div className="grid grid-cols-2 gap-4">
        <div className="bg-blue-100 p-4 rounded-2xl flex flex-col items-center justify-center shadow-sm">
          <Milk className="w-8 h-8 text-blue-500 mb-2" />
          <span className="text-xs text-blue-400 font-bold uppercase tracking-wider">今日奶量</span>
          <span className="text-2xl font-extrabold text-blue-700">{stats.totalMilk} ml</span>
        </div>

        <div className="bg-indigo-100 p-4 rounded-2xl flex flex-col items-center justify-center shadow-sm">
          <Moon className="w-8 h-8 text-indigo-500 mb-2" />
          <span className="text-xs text-indigo-400 font-bold uppercase tracking-wider">今日累計</span>
          <span className="text-2xl font-extrabold text-indigo-700">
            {Math.floor(stats.totalSleepMinutes / 60)}小時 {stats.totalSleepMinutes % 60}分
          </span>
        </div>

        <div className="bg-amber-100 p-4 rounded-2xl flex flex-col items-center justify-center shadow-sm">
          <Baby className="w-8 h-8 text-amber-500 mb-2" />
          <span className="text-xs text-amber-400 font-bold uppercase tracking-wider">換片次數</span>
          <span className="text-2xl font-extrabold text-amber-700">{stats.diaperCount}</span>
        </div>

        <div className="bg-emerald-100 p-4 rounded-2xl flex flex-col items-center justify-center shadow-sm">
          <Clock className="w-8 h-8 text-emerald-500 mb-2" />
          <span className="text-xs text-emerald-400 font-bold uppercase tracking-wider">上次餵奶</span>
          <span className="text-xl font-extrabold text-emerald-700">{stats.timeSinceFeed}</span>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { LogType, FeedType, DiaperType, BabyLog } from '../types';
import { PlusCircle, CalendarDays, Moon, ArrowRight, Play, Square, History } from 'lucide-react';

interface LogFormProps {
  onAddLog: (log: BabyLog) => void;
  isSleeping: boolean;
  sleepStartTime: string | null;
  onStartSleep: (startTime: string) => void;
  onEndSleep: (log: BabyLog) => void;
}

export const LogForm: React.FC<LogFormProps> = ({ onAddLog, isSleeping, sleepStartTime, onStartSleep, onEndSleep }) => {
  const [activeType, setActiveType] = useState<LogType>(LogType.FEED);
  const [mode, setMode] = useState<'LIVE' | 'MANUAL'>('LIVE'); // For Sleep Tab

  // Time helper
  const toLocalISO = (date: Date) => {
    const offset = date.getTimezoneOffset() * 60000;
    return new Date(date.getTime() - offset).toISOString().slice(0, 16);
  };

  // Form States
  const [amount, setAmount] = useState<number>(120);
  const [feedType, setFeedType] = useState<FeedType>(FeedType.FORMULA);
  const [diaperStatus, setDiaperStatus] = useState<DiaperType>(DiaperType.WET);

  // Sleep specific states
  const [startSleepInput, setStartSleepInput] = useState<string>(toLocalISO(new Date())); // For LIVE start
  const [endSleepInput, setEndSleepInput] = useState<string>(toLocalISO(new Date())); // For LIVE end

  // Manual sleep states
  const [manualSleepStart, setManualSleepStart] = useState<string>(toLocalISO(new Date(Date.now() - 60 * 60 * 1000)));
  const [manualSleepEnd, setManualSleepEnd] = useState<string>(toLocalISO(new Date()));

  const [weight, setWeight] = useState<number>(3.5);
  const [height, setHeight] = useState<number>(50);
  const [headCirc, setHeadCirc] = useState<number>(35);
  const [otherDetails, setOtherDetails] = useState<string>("");

  const [date, setDate] = useState<string>(toLocalISO(new Date()));

  // Sync End Sleep Input with current time when component mounts or updates
  useEffect(() => {
    const timer = setInterval(() => {
        if (isSleeping) {
            setEndSleepInput(toLocalISO(new Date()));
        } else {
            setStartSleepInput(toLocalISO(new Date()));
        }
    }, 60000);
    return () => clearInterval(timer);
  }, [isSleeping]);

  // Quick Time Adjustments (Only for non-sleep logs)
  const setQuickTime = (minutesOffset: number) => {
    const now = new Date();
    now.setMinutes(now.getMinutes() + minutesOffset);
    setDate(toLocalISO(now));
  };

  // Handle Live Sleep Actions
  const handleStartSleeping = () => {
    // Save start time to DB status
    const start = new Date(startSleepInput).toISOString();
    onStartSleep(start);
  };

  const handleWakeUp = () => {
    if (!sleepStartTime) return;

    const start = new Date(sleepStartTime).getTime();
    const end = new Date(endSleepInput).getTime();
    const duration = Math.floor((end - start) / (1000 * 60));

    if (duration <= 0) {
        alert("起床時間必須晚於入睡時間");
        return;
    }

    const newLog: BabyLog = {
        id: Date.now().toString(),
        timestamp: new Date(endSleepInput).toISOString(), // Log timestamp is usually the end time
        type: LogType.SLEEP,
        durationMinutes: duration
    };

    onEndSleep(newLog);
  };

  // Handle Manual Form Submission
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    let newLog: BabyLog;
    const id = Date.now().toString();

    // Manual Sleep Entry
    if (activeType === LogType.SLEEP && mode === 'MANUAL') {
        const start = new Date(manualSleepStart).getTime();
        const end = new Date(manualSleepEnd).getTime();
        const duration = Math.floor((end - start) / (1000 * 60));

        if (duration <= 0) {
            alert("結束時間必須晚於開始時間");
            return;
        }

        newLog = {
            id,
            timestamp: new Date(manualSleepEnd).toISOString(),
            type: LogType.SLEEP,
            durationMinutes: duration
        };
    } else {
        // Standard Logs
        const baseLog = {
            id,
            timestamp: new Date(date).toISOString(),
        };

        switch (activeType) {
            case LogType.FEED:
                newLog = { ...baseLog, type: LogType.FEED, amountMl: Number(amount), feedType } as any;
                break;
            case LogType.DIAPER:
                newLog = { ...baseLog, type: LogType.DIAPER, status: diaperStatus } as any;
                break;
            case LogType.HEALTH:
                newLog = { ...baseLog, type: LogType.HEALTH, weightKg: Number(weight), heightCm: Number(height), headCircumferenceCm: Number(headCirc) } as any;
                break;
            case LogType.OTHER:
                newLog = { ...baseLog, type: LogType.OTHER, details: otherDetails } as any;
                break;
            default:
                return;
        }
    }

    onAddLog(newLog);

    // Reset fields
    const now = new Date();
    setDate(toLocalISO(now));
    setOtherDetails("");
  };

  const TabButton = ({ type, label }: { type: LogType, label: string }) => (
    <button
      type="button"
      onClick={() => { setActiveType(type); setMode('LIVE'); }}
      className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all duration-200 whitespace-nowrap px-2 ${
        activeType === type 
        ? 'bg-blue-600 text-white shadow-md transform scale-105' 
        : 'bg-white text-gray-500 border border-gray-200 hover:bg-gray-50'
      }`}
    >
      {label}
    </button>
  );

  return (
    <div className="bg-white rounded-3xl shadow-lg p-6 mb-6">
      <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center gap-2">
        <PlusCircle className="w-6 h-6 text-blue-500" />
        新增記錄
      </h2>

      <div className="flex gap-2 mb-6 overflow-x-auto no-scrollbar pb-1">
        <TabButton type={LogType.FEED} label="飲食" />
        <TabButton type={LogType.DIAPER} label="尿片" />
        <TabButton type={LogType.SLEEP} label="睡眠" />
        <TabButton type={LogType.HEALTH} label="健康" />
        <TabButton type={LogType.OTHER} label="其他" />
      </div>

      {/* SLEEP TAB SPECIAL HANDLING */}
      {activeType === LogType.SLEEP ? (
          <div>
             <div className="flex bg-gray-100 p-1 rounded-xl mb-4">
                <button 
                    onClick={() => setMode('LIVE')}
                    className={`flex-1 py-1.5 rounded-lg text-sm font-bold transition-all ${mode === 'LIVE' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500'}`}
                >
                    即時開關
                </button>
                <button 
                    onClick={() => setMode('MANUAL')}
                    className={`flex-1 py-1.5 rounded-lg text-sm font-bold transition-all flex items-center justify-center gap-1 ${mode === 'MANUAL' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500'}`}
                >
                    <History className="w-3 h-3" />
                    手動補登
                </button>
             </div>

             {mode === 'LIVE' && (
                 <div className="bg-indigo-50 p-6 rounded-2xl text-center border border-indigo-100">
                    {isSleeping ? (
                        <>
                           <div className="mb-4 text-indigo-800 font-bold">Jacob 正在睡覺...</div>
                           <label className="block text-xs text-indigo-400 mb-1 text-left">起床時間</label>
                           <input
                                type="datetime-local"
                                value={endSleepInput}
                                onChange={(e) => setEndSleepInput(e.target.value)}
                                className="w-full p-3 rounded-xl bg-white border border-indigo-200 focus:ring-2 focus:ring-indigo-500 outline-none mb-4"
                            />
                           <button 
                              onClick={handleWakeUp}
                              className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white font-black rounded-xl shadow-lg shadow-indigo-200 transition-all flex items-center justify-center gap-2 text-lg"
                           >
                              <Square className="w-5 h-5 fill-current" />
                              起床 (停止計時)
                           </button>
                        </>
                    ) : (
                        <>
                           <label className="block text-xs text-indigo-400 mb-1 text-left">入睡時間</label>
                           <input
                                type="datetime-local"
                                value={startSleepInput}
                                onChange={(e) => setStartSleepInput(e.target.value)}
                                className="w-full p-3 rounded-xl bg-white border border-indigo-200 focus:ring-2 focus:ring-indigo-500 outline-none mb-4"
                            />
                           <button 
