                >
                   <Ruler className="w-5 h-5" />
                   <span className="text-xs font-bold">身高</span>
                </button>
                <button
                   type="button"
                   onClick={() => setHealthSubType('HEAD')}
                   className={`flex-1 py-3 rounded-xl flex flex-col items-center justify-center gap-1 transition-all ${healthSubType === 'HEAD' ? 'bg-emerald-100 text-emerald-700 border-2 border-emerald-500 shadow-sm' : 'bg-gray-50 border border-gray-200 text-gray-500'}`}
                >
                   <Activity className="w-5 h-5" />
                   <span className="text-xs font-bold">頭圍</span>
                </button>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                   {healthSubType === 'WEIGHT' ? '重量 (kg)' : '長度 (cm)'}
                </label>
                <input
                    type="number"
                    step="0.01"
                    value={healthValue}
                    onChange={(e) => setHealthValue(e.target.value)}
                    placeholder={healthSubType === 'WEIGHT' ? '3.5' : '50.0'}
                    className="w-full p-4 text-xl font-bold text-center rounded-xl bg-emerald-50 border border-emerald-200 focus:ring-2 focus:ring-emerald-500 outline-none text-emerald-800"
                    autoFocus
                />
              </div>
            </div>
            )}

            {activeType === LogType.OTHER && (
            <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">事項內容</label>
                <textarea
                rows={3}
                value={otherDetails}
                onChange={(e) => setOtherDetails(e.target.value)}
                placeholder="例如：洗澡、肚仔痛、打針、趴趴時間..."
                className="w-full p-3 rounded-xl bg-gray-50 border border-gray-200 focus:ring-2 focus:ring-pink-500 outline-none text-gray-700"
                required
                />
            </div>
            )}

            <button
            type="submit"
            className="w-full mt-4 py-3 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-xl shadow-md transition-colors flex items-center justify-center gap-2"
            >
            儲存記錄
            </button>
        </form>
      )}
    </div>
  );
};

import React, { useMemo, useState } from 'react';
import { BabyLog, LogType, HealthLog } from '../types';
import { Activity, Weight, Ruler } from 'lucide-react';

interface HealthChartProps {
  logs: BabyLog[];
}

type HealthMetric = 'WEIGHT' | 'HEIGHT' | 'HEAD';

export const HealthChart: React.FC<HealthChartProps> = ({ logs }) => {
  const [metric, setMetric] = useState<HealthMetric>('WEIGHT');

  // Filter and prepare data
  const data = useMemo(() => {
    // 1. Filter only health logs
    const healthLogs = logs.filter(l => l.type === LogType.HEALTH) as HealthLog[];

    // 2. Extract relevant metric and sort by date ascending
    const points = healthLogs
      .map(l => {
        let value = 0;
        if (metric === 'WEIGHT') value = l.weightKg || 0;
        if (metric === 'HEIGHT') value = l.heightCm || 0;
        if (metric === 'HEAD') value = l.headCircumferenceCm || 0;

        return {
            date: new Date(l.timestamp),
            value: value,
            id: l.id
        };
      })
      .filter(p => p.value > 0) // Remove entries without the selected metric
      .sort((a, b) => a.date.getTime() - b.date.getTime()); // Sort Chronologically

    return points;
  }, [logs, metric]);

  // Chart Dimensions
  const height = 200;
  const padding = 20;

  // Render Logic
  const renderChart = () => {
    if (data.length < 2) {
        return (
            <div className="h-[200px] flex items-center justify-center text-gray-400 text-sm bg-gray-50 rounded-xl border border-dashed border-gray-200">
                需要至少兩筆{getLabel()}記錄來顯示趨勢
            </div>
        );
    }

    const minVal = Math.min(...data.map(d => d.value)) * 0.95; // 5% buffer bottom
    const maxVal = Math.max(...data.map(d => d.value)) * 1.05; // 5% buffer top
    const range = maxVal - minVal;

    // Helper to scale Y
    const getY = (val: number) => {
        return height - ((val - minVal) / range) * (height - padding * 2) - padding;
    };

    // Helper to scale X
    // We space points equally to make it readable, rather than strictly by time, 
    // but show dates on X axis.
    const getX = (index: number) => {
        return (index / (data.length - 1)) * 100;
    };

    // Build SVG Path
    const pathD = data.map((d, i) => {
        const x = getX(i);
        const y = getY(d.value);
        return `${i === 0 ? 'M' : 'L'} ${x}% ${y}`;
    }).join(' ');

    return (
        <div className="relative h-[220px] w-full mt-4 select-none">
            {/* Y Axis Labels (Min/Max) */}
            <div className="absolute left-0 top-0 bottom-6 w-full pointer-events-none opacity-20">
                <div className="border-t border-emerald-500 w-full absolute" style={{ top: padding }}></div>
                <div className="border-t border-emerald-500 w-full absolute" style={{ bottom: padding }}></div>
            </div>

            <svg className="w-full h-[200px] overflow-visible">
                {/* Gradient Definition */}
                <defs>
                    <linearGradient id="lineGradient" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="0%" stopColor="#10b981" stopOpacity="0.2"/>
                        <stop offset="100%" stopColor="#10b981" stopOpacity="0"/>
                    </linearGradient>
                </defs>

                {/* Area under curve (Optional, requires closing path) */}
                {/* Line */}
                <path 
                    d={pathD} 
                    fill="none" 
                    stroke="#10b981" 
                    strokeWidth="3" 
                    strokeLinecap="round" 
                    strokeLinejoin="round"
                    className="drop-shadow-sm"
                />

                {/* Dots & Labels */}
                {data.map((d, i) => {
                    const y = getY(d.value);
                    const xPct = getX(i);

                    return (
                        <g key={d.id}>
                            {/* Dot */}
                            <circle cx={`${xPct}%`} cy={y} r="4" fill="white" stroke="#10b981" strokeWidth="2" />

                            {/* Value Label */}
                            <text 
                                x={`${xPct}%`} 
                                y={y - 12} 
                                textAnchor="middle" 
                                fill="#047857" 
                                fontSize="11" 
                                fontWeight="bold"
                            >
                                {d.value}
                            </text>

                            {/* Date Label (Bottom) */}
                            <text 
                                x={`${xPct}%`} 
                                y={215} 
                                textAnchor="middle" 
                                fill="#9ca3af" 
                                fontSize="10"
                            >
                                {d.date.toLocaleDateString('zh-TW', {month:'numeric', day:'numeric'})}
                            </text>
                        </g>
                    );
                })}
            </svg>
        </div>
    );
  };

  const getLabel = () => {
      if (metric === 'WEIGHT') return '體重';
      if (metric === 'HEIGHT') return '身高';
      return '頭圍';
  }

  return (
    <div className="bg-white p-5 rounded-3xl shadow-sm border border-gray-100 mt-6">
       <div className="flex flex-col gap-4">
          <h3 className="font-bold text-gray-800 flex items-center gap-2">
              <Activity className="w-5 h-5 text-emerald-500" />
              生長曲線
          </h3>

          <div className="flex gap-2 bg-gray-50 p-1 rounded-xl w-fit">
             <button
                onClick={() => setMetric('WEIGHT')}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-1 ${metric === 'WEIGHT' ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-500'}`}
             >
                <Weight className="w-3 h-3" /> 體重
             </button>
             <button
                onClick={() => setMetric('HEIGHT')}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-1 ${metric === 'HEIGHT' ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-500'}`}
             >
                <Ruler className="w-3 h-3" /> 身高
             </button>
             <button
                onClick={() => setMetric('HEAD')}
                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-1 ${metric === 'HEAD' ? 'bg-white text-emerald-600 shadow-sm' : 'text-gray-500'}`}
             >
                <Activity className="w-3 h-3" /> 頭圍
             </button>
          </div>
       </div>

       {renderChart()}

       {data.length > 0 && (
           <div className="mt-4 text-center">
              <p className="text-xs text-gray-400">
                 最新{getLabel()}: <span className="font-bold text-emerald-600 text-sm">{data[data.length-1].value} {metric === 'WEIGHT' ? 'kg' : 'cm'}</span>
              </p>
           </div>
       )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BabyLog, LogType, FeedLog, SleepLog } from './types';
import { subscribeToLogs, subscribeToSleepStatus, addLogToCloud, deleteLogFromCloud, exportLogsToJSON, setSleepStatus, clearSleepStatus } from './services/storageService';
import { isConfigured } from './services/firebase'; // Import configuration check
import { generateBabyInsights } from './services/geminiService';
import { Dashboard } from './components/Dashboard';
import { LogForm } from './components/LogForm';
import { LogList } from './components/LogList';
import { TrendsChart } from './components/TrendsChart';
import { HealthChart } from './components/HealthChart'; // Import new chart
import { Sparkles, Download, Baby, CloudLightning, Settings, ExternalLink, Calendar, ChevronLeft, ChevronRight, Milk, Moon, Layers } from 'lucide-react';
import { BABY_NAME, BIRTH_DATE } from './constants';

const App: React.FC = () => {
  // 1. 檢查 Firebase 是否已設定，如果沒設定，顯示教學畫面
  if (!isConfigured) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50 p-6">
        <div className="bg-white p-8 rounded-3xl shadow-xl max-w-md w-full border border-gray-100">
           <div className="flex justify-center mb-6">
             <div className="bg-red-100 p-4 rounded-full">
               <Settings className="w-10 h-10 text-red-500" />
             </div>
           </div>
           <h1 className="text-2xl font-black text-gray-800 mb-4 text-center">尚未連結資料庫</h1>
           <p className="text-gray-600 mb-6 text-center leading-relaxed">
             為了啟用同步功能，您需要連結 Firebase 資料庫。請按照以下步驟操作：
           </p>

           <ol className="space-y-4 text-sm text-gray-700 bg-gray-50 p-5 rounded-xl border border-gray-200 mb-6">
             <li className="flex gap-2">
               <span className="font-bold text-blue-600">1.</span>
               <span>前往 <a href="https://console.firebase.google.com/" target="_blank" className="text-blue-600 underline flex items-center gap-1 inline-flex">Firebase Console <ExternalLink className="w-3 h-3"/></a></span>
             </li>
             <li className="flex gap-2">
               <span className="font-bold text-blue-600">2.</span>
               <span>建立新專案，接著建立 <b>Web App</b>。</span>
             </li>
             <li className="flex gap-2">
               <span className="font-bold text-blue-600">3.</span>
               <span>複製 <b>Config</b> 程式碼片段。</span>
             </li>
             <li className="flex gap-2">
               <span className="font-bold text-blue-600">4.</span>
               <span>開啟程式碼中的 <code>services/firebase.ts</code> 檔案，貼上設定。</span>
             </li>
           </ol>

           <div className="text-center text-xs text-gray-400">
             完成後，請重新整理此頁面。
           </div>
        </div>
      </div>
    );
  }

  // Helper: Get Local ISO Date string (YYYY-MM-DD)
  const getLocalDateString = (date: Date) => {
    const offset = date.getTimezoneOffset() * 60000;
    return new Date(date.getTime() - offset).toISOString().split('T')[0];
  };

  const [logs, setLogs] = useState<BabyLog[]>([]);
  const [sleepStartTime, setSleepStartTime] = useState<string | null>(null);
  const [insight, setInsight] = useState<string>("");
  const [loadingInsight, setLoadingInsight] = useState(false);
  const [selectedDate, setSelectedDate] = useState<string>(getLocalDateString(new Date()));

  // 啟動時訂閱雲端資料
  useEffect(() => {
    const unsubscribeLogs = subscribeToLogs((updatedLogs) => {
      setLogs(updatedLogs);
    });
    const unsubscribeSleep = subscribeToSleepStatus((startTime) => {
      setSleepStartTime(startTime);
    });
    return () => {
      unsubscribeLogs();
      unsubscribeSleep();
    };
  }, []);

  // 新增時直接傳到雲端
  const handleAddLog = (newLog: BabyLog) => {
    addLogToCloud(newLog);
    // 如果新增的日期不是當前選擇的日期，自動切換到新增的那一天 (UX 優化)
    const logDate = getLocalDateString(new Date(newLog.timestamp));
    if (logDate !== selectedDate) {
      setSelectedDate(logDate);
    }
  };

  // 處理睡眠狀態變更
  const handleSleepStart = (startTime: string) => {
    setSleepStatus(startTime);
  };

  const handleSleepEnd = (log: BabyLog) => {
    addLogToCloud(log);
    clearSleepStatus();
    // 自動切換到記錄日期
    const logDate = getLocalDateString(new Date(log.timestamp));
    if (logDate !== selectedDate) {
      setSelectedDate(logDate);
    }
  };

  // 刪除時直接通知雲端
  const handleDeleteLog = (id: string) => {
    if (confirm("確定刪除這條記錄嗎？")) {
      deleteLogFromCloud(id);
    }
  };

  const handleGetInsight = async () => {
    if (logs.length === 0) return;
    setLoadingInsight(true);
    const result = await generateBabyInsights(logs);
    setInsight(result);
    setLoadingInsight(false);
  };

  // Change Date Helper
  const changeDate = (days: number) => {
    const date = new Date(selectedDate);
    date.setDate(date.getDate() + days);
    setSelectedDate(getLocalDateString(date));
  };

  // Filter logs based on selected date
  const filteredLogs = useMemo(() => {
    return logs.filter(log => {
      const logDateStr = getLocalDateString(new Date(log.timestamp));
      return logDateStr === selectedDate;
    });
  }, [logs, selectedDate]);

  // Calculate stats for the selected date
  const dailyStats = useMemo(() => {
    const totalMilk = filteredLogs
      .filter(l => l.type === LogType.FEED)
      .reduce((sum, l) => sum + ((l as FeedLog).amountMl || 0), 0);

    const totalSleepMinutes = filteredLogs
      .filter(l => l.type === LogType.SLEEP)
      .reduce((sum, l) => sum + ((l as SleepLog).durationMinutes || 0), 0);

    const diaperCount = filteredLogs.filter(l => l.type === LogType.DIAPER).length;

    return { totalMilk, totalSleepMinutes, diaperCount };
  }, [filteredLogs]);

  // Calculate Age
  const birth = new Date(BIRTH_DATE);
  const now = new Date();
  const birthDay = new Date(birth.getFullYear(), birth.getMonth(), birth.getDate());
  const currentDay = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const diffTime = currentDay.getTime() - birthDay.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1; 

  const todayStr = new Date().toLocaleDateString('zh-TW', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    weekday: 'short'
  });

  return (
    <div className="min-h-screen pb-20 max-w-md mx-auto bg-gray-50 shadow-2xl overflow-hidden min-w-[320px]">
      {/* Header */}
      <header className="bg-white px-6 pt-8 pb-8 rounded-b-[2.5rem] shadow-sm mb-6">
        <div className="flex flex-col items-center mb-6">
          <p className="text-gray-500 font-bold text-sm tracking-wide mb-1">{todayStr}</p>
          <h1 className="text-4xl font-black text-gray-800 tracking-tight mb-3">{BABY_NAME}</h1>

          <div className="flex items-center gap-2 bg-blue-50 border border-blue-100 px-4 py-1.5 rounded-full">
            <Baby className="w-4 h-4 text-blue-500" />
            <span className="text-blue-600 font-bold text-sm">
              出生第 {diffDays} 天
            </span>
          </div>
          <div className="mt-2 flex items-center gap-1 text-xs text-green-600 bg-green-50 px-2 py-0.5 rounded-full">
             <CloudLightning className="w-3 h-3" />
             <span>雲端同步中</span>
          </div>
        </div>

        {/* Main Dashboard (Always shows TODAY's snapshot) */}
        <Dashboard 
          logs={logs} 
          isSleeping={!!sleepStartTime} 
          sleepStartTime={sleepStartTime}
        />
      </header>

      <main className="px-5 space-y-8">
        {/* Input Form */}
        <section>
          <LogForm 
            onAddLog={handleAddLog} 
            isSleeping={!!sleepStartTime}
            sleepStartTime={sleepStartTime}
            onStartSleep={handleSleepStart}
            onEndSleep={handleSleepEnd}
          />
        </section>

        {/* AI Insight Section */}
        <section>
           <div className="flex items-center justify-between mb-3">
              <h2 className="font-bold text-gray-800 text-lg flex items-center gap-2">
                <Sparkles className="w-5 h-5 text-purple-500" />
                AI 成長分析
              </h2>
              <button 
                onClick={handleGetInsight}
                disabled={loadingInsight || logs.length === 0}
                className="text-xs font-bold text-purple-600 bg-purple-50 px-3 py-1.5 rounded-lg hover:bg-purple-100 disabled:opacity-50"
              >
                {loadingInsight ? '分析中...' : '重新分析'}
              </button>
           </div>

           {insight && (
             <div className="bg-purple-50 p-4 rounded-2xl text-sm text-gray-700 leading-relaxed border border-purple-100 shadow-sm animate-fade-in">
               <div className="whitespace-pre-line">{insight}</div>
             </div>
           )}
           {!insight && (
             <div className="bg-white p-4 rounded-2xl text-sm text-gray-400 text-center border border-gray-100 border-dashed">
               點擊分析以獲取 Jacob 的每週成長摘要。
             </div>
           )}
        </section>

        {/* History & Logs Section */}
        <section>
          <div className="flex items-center justify-between mb-4">
             <h2 className="font-bold text-gray-800 text-lg flex items-center gap-2">
               <Calendar className="w-5 h-5 text-gray-600" />
               歷史記錄
             </h2>
          </div>

          {/* Date Picker Control */}
          <div className="bg-white p-2 rounded-2xl shadow-sm border border-gray-100 mb-4 flex items-center justify-between">
            <button onClick={() => changeDate(-1)} className="p-2 hover:bg-gray-100 rounded-xl text-gray-500">
              <ChevronLeft className="w-5 h-5" />
            </button>
            <div className="relative">
              <input 
                type="date" 
                value={selectedDate}
                onChange={(e) => setSelectedDate(e.target.value)}
                className="font-bold text-gray-700 bg-transparent border-none focus:ring-0 text-center text-lg outline-none cursor-pointer"
              />
            </div>
            <button onClick={() => changeDate(1)} className="p-2 hover:bg-gray-100 rounded-xl text-gray-500" disabled={selectedDate >= getLocalDateString(new Date())}>
              <ChevronRight className="w-5 h-5" />
            </button>
          </div>

          {/* Daily Mini Stats */}
          <div className="grid grid-cols-3 gap-2 mb-4">
             <div className="bg-blue-50 rounded-xl p-2 flex flex-col items-center justify-center border border-blue-100">
                <div className="flex items-center gap-1 mb-1">
                   <Milk className="w-3 h-3 text-blue-400" />
                   <span className="text-[10px] text-blue-400 font-bold uppercase">奶量</span>
                </div>
                <span className="text-sm font-black text-blue-700">{dailyStats.totalMilk} ml</span>
             </div>
             <div className="bg-indigo-50 rounded-xl p-2 flex flex-col items-center justify-center border border-indigo-100">
                <div className="flex items-center gap-1 mb-1">
                   <Moon className="w-3 h-3 text-indigo-400" />
                   <span className="text-[10px] text-indigo-400 font-bold uppercase">睡眠</span>
                </div>
                <span className="text-sm font-black text-indigo-700">
                   {Math.floor(dailyStats.totalSleepMinutes / 60)}h {dailyStats.totalSleepMinutes % 60}m
                </span>
             </div>
             <div className="bg-amber-50 rounded-xl p-2 flex flex-col items-center justify-center border border-amber-100">
                <div className="flex items-center gap-1 mb-1">
                   <Layers className="w-3 h-3 text-amber-400" />
                   <span className="text-[10px] text-amber-400 font-bold uppercase">換片</span>
                </div>
                <span className="text-sm font-black text-amber-700">{dailyStats.diaperCount}</span>
             </div>
          </div>

          <LogList logs={filteredLogs} onDeleteLog={handleDeleteLog} />
        </section>

        {/* Trends Chart Section (Existing) */}
        <section>
          <TrendsChart logs={logs} />
        </section>

        {/* Health Chart Section (NEW) */}
        <section>
          <HealthChart logs={logs} />
        </section>

        {/* Settings / Tools */}
        <section className="pt-4 border-t border-gray-200">
           <div className="grid grid-cols-1 gap-3">
             <button 
               onClick={() => exportLogsToJSON(logs)}
               className="py-3 flex items-center justify-center gap-2 text-gray-500 bg-white border border-gray-200 rounded-xl hover:bg-gray-50 transition-colors text-sm font-semibold"
             >
               <Download className="w-4 h-4" />
               匯出備份 (JSON)
             </button>
           </div>
           <p className="text-center text-xs text-gray-400 mt-2">
             * 資料已啟用即時雲端同步
           </p>
        </section>
      </main>
    </div>
  );
};

