              <h2 className="font-bold text-gray-800 text-lg flex items-center gap-2">
                <Sparkles className="w-5 h-5 text-purple-500" />
                AI 成長分析
              </h2>
              <button 
                onClick={handleGetInsight}
                disabled={loadingInsight || logs.length === 0}
                className="text-xs font-bold text-purple-600 bg-purple-50 px-3 py-1.5 rounded-lg hover:bg-purple-100 disabled:opacity-50"
              >
                {loadingInsight ? '分析中...' : '重新分析'}
              </button>
           </div>

           {insight && (
             <div className="bg-purple-50 p-4 rounded-2xl text-sm text-gray-700 leading-relaxed border border-purple-100 shadow-sm animate-fade-in">
               <div className="whitespace-pre-line">{insight}</div>
             </div>
           )}
           {!insight && (
             <div className="bg-white p-4 rounded-2xl text-sm text-gray-400 text-center border border-gray-100 border-dashed">
               點擊分析以獲取 Jacob 的每週成長摘要。
             </div>
           )}
        </section>

        {/* History & Logs Section */}
        <section>
          <div className="flex items-center justify-between mb-4">
             <h2 className="font-bold text-gray-800 text-lg flex items-center gap-2">
               <Calendar className="w-5 h-5 text-gray-600" />
               歷史記錄
             </h2>
          </div>

          {/* Date Picker Control */}
          <div className="bg-white p-2 rounded-2xl shadow-sm border border-gray-100 mb-4 flex items-center justify-between">
            <button onClick={() => changeDate(-1)} className="p-2 hover:bg-gray-100 rounded-xl text-gray-500">
              <ChevronLeft className="w-5 h-5" />
            </button>
            <div className="relative">
              <input 
                type="date" 
                value={selectedDate}
                onChange={(e) => setSelectedDate(e.target.value)}
                className="font-bold text-gray-700 bg-transparent border-none focus:ring-0 text-center text-lg outline-none cursor-pointer"
              />
            </div>
            <button onClick={() => changeDate(1)} className="p-2 hover:bg-gray-100 rounded-xl text-gray-500" disabled={selectedDate >= getLocalDateString(new Date())}>
              <ChevronRight className="w-5 h-5" />
            </button>
          </div>

          {/* Daily Mini Stats */}
          <div className="grid grid-cols-3 gap-2 mb-4">
             <div className="bg-blue-50 rounded-xl p-2 flex flex-col items-center justify-center border border-blue-100">
                <div className="flex items-center gap-1 mb-1">
                   <Milk className="w-3 h-3 text-blue-400" />
                   <span className="text-[10px] text-blue-400 font-bold uppercase">奶量</span>
                </div>
                <span className="text-sm font-black text-blue-700">{dailyStats.totalMilk} ml</span>
             </div>
             <div className="bg-indigo-50 rounded-xl p-2 flex flex-col items-center justify-center border border-indigo-100">
                <div className="flex items-center gap-1 mb-1">
                   <Moon className="w-3 h-3 text-indigo-400" />
                   <span className="text-[10px] text-indigo-400 font-bold uppercase">睡眠</span>
                </div>
                <span className="text-sm font-black text-indigo-700">
                   {Math.floor(dailyStats.totalSleepMinutes / 60)}h {dailyStats.totalSleepMinutes % 60}m
                </span>
             </div>
             <div className="bg-amber-50 rounded-xl p-2 flex flex-col items-center justify-center border border-amber-100">
                <div className="flex items-center gap-1 mb-1">
                   <Layers className="w-3 h-3 text-amber-400" />
                   <span className="text-[10px] text-amber-400 font-bold uppercase">換片</span>
                </div>
                <span className="text-sm font-black text-amber-700">{dailyStats.diaperCount}</span>
             </div>
          </div>

          <LogList logs={filteredLogs} onDeleteLog={handleDeleteLog} feedIntervals={feedIntervals} />
        </section>

        {/* Trends Chart Section (Existing) */}
        <section>
          <TrendsChart logs={logs} />
        </section>

        {/* Health Chart Section (NEW) */}
        <section>
          <HealthChart logs={logs} />
        </section>

        {/* Settings / Tools */}
        <section className="pt-4 border-t border-gray-200">
           <div className="grid grid-cols-1 gap-3">
             <button 
               onClick={() => exportLogsToJSON(logs)}
               className="py-3 flex items-center justify-center gap-2 text-gray-500 bg-white border border-gray-200 rounded-xl hover:bg-gray-50 transition-colors text-sm font-semibold"
             >
               <Download className="w-4 h-4" />
               匯出備份 (JSON)
             </button>
           </div>
           <p className="text-center text-xs text-gray-400 mt-2">
             * 資料已啟用即時雲端同步
           </p>
        </section>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { BabyLog, LogType, FeedLog, DiaperLog, SleepLog, HealthLog, OtherLog } from '../types';
import { Milk, Baby, Moon, Activity, Trash2, StickyNote, Sunrise, Sun, Sunset, MoonStar, Clock } from 'lucide-react';

interface LogListProps {
  logs: BabyLog[];
  onDeleteLog: (id: string) => void;
  feedIntervals?: Record<string, string>;
}

export const LogList: React.FC<LogListProps> = ({ logs, onDeleteLog, feedIntervals }) => {
  // Sort by date desc
  const sortedLogs = [...logs].sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

  const getIcon = (type: LogType) => {
    switch (type) {
      case LogType.FEED: return <Milk className="w-5 h-5 text-blue-500" />;
      case LogType.DIAPER: return <Baby className="w-5 h-5 text-amber-500" />;
      case LogType.SLEEP: return <Moon className="w-5 h-5 text-indigo-500" />;
      case LogType.HEALTH: return <Activity className="w-5 h-5 text-emerald-500" />;
      case LogType.OTHER: return <StickyNote className="w-5 h-5 text-pink-500" />;
    }
  };

  // Helper to determine time period styling
  const getTimePeriodStyle = (dateStr: string) => {
    const date = new Date(dateStr);
    const hour = date.getHours();

    // 00:00 - 05:59: 凌晨 (Late Night)
    if (hour < 6) {
      return {
        label: '凌晨',
        icon: <MoonStar className="w-3 h-3" />,
        bgColor: 'bg-indigo-50',
        textColor: 'text-indigo-400',
        borderColor: 'border-indigo-300'
      };
    }
    // 06:00 - 11:59: 早上 (Morning)
    if (hour < 12) {
      return {
        label: '早上',
        icon: <Sunrise className="w-3 h-3" />,
        bgColor: 'bg-amber-50',
        textColor: 'text-amber-500',
        borderColor: 'border-amber-300'
      };
    }
    // 12:00 - 17:59: 下午 (Afternoon)
    if (hour < 18) {
      return {
        label: '下午',
        icon: <Sun className="w-3 h-3" />,
        bgColor: 'bg-sky-50',
        textColor: 'text-sky-500',
        borderColor: 'border-sky-300'
      };
    }
    // 18:00 - 23:59: 晚上 (Evening)
    return {
      label: '晚上',
      icon: <Sunset className="w-3 h-3" />,
      bgColor: 'bg-slate-50',
      textColor: 'text-slate-500',
      borderColor: 'border-slate-300'
    };
  };

  const getDetails = (log: BabyLog) => {
    switch (log.type) {
      case LogType.FEED:
        const f = log as FeedLog;
        return `${f.amountMl}ml - ${f.feedType}`;
      case LogType.DIAPER:
        return (log as DiaperLog).status;
      case LogType.SLEEP:
        // Calculate start time based on end time (timestamp) and duration
        const durationMins = (log as SleepLog).durationMinutes;
        const endTime = new Date(log.timestamp);
        const startTime = new Date(endTime.getTime() - durationMins * 60000);

        const formatTime = (d: Date) => d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

        const hours = Math.floor(durationMins / 60);
        const mins = durationMins % 60;
        const durationStr = `${hours > 0 ? `${hours}小時 ` : ''}${mins}分鐘`;

        return `${formatTime(startTime)} - ${formatTime(endTime)}\n(${durationStr})`;
      case LogType.HEALTH:
        const h = log as HealthLog;
        return [
           h.weightKg ? `${h.weightKg}kg` : '',
           h.heightCm ? `${h.heightCm}cm` : '',
           h.headCircumferenceCm ? `頭圍 ${h.headCircumferenceCm}cm` : ''
        ].filter(Boolean).join(', ');
      case LogType.OTHER:
        return (log as OtherLog).details;
      default: return '';
    }
  };

  return (
    <div className="space-y-3">
      {sortedLogs.map((log) => {
        const timeStyle = getTimePeriodStyle(log.timestamp);
        const feedInterval = (log.type === LogType.FEED && feedIntervals) ? feedIntervals[log.id] : null;

        return (
          <div 
            key={log.id} 
            className={`bg-white rounded-xl shadow-sm flex items-center justify-between animate-fade-in overflow-hidden border-l-[6px] ${timeStyle.borderColor}`}
          >
            <div className="flex items-center gap-3 p-4 w-full">
              {/* Icon Circle */}
              <div className={`p-2.5 rounded-full ${timeStyle.bgColor} flex-shrink-0`}>
                {getIcon(log.type)}
              </div>

              <div className="flex-grow min-w-0">
                <div className="flex items-center gap-2 mb-1 flex-wrap">
                   {/* Time Badge */}
                   <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded-md flex items-center gap-1 ${timeStyle.bgColor} ${timeStyle.textColor}`}>
                      {timeStyle.icon}
                      {timeStyle.label}
                   </span>
                   {/* Actual Time */}
                   <span className="font-bold text-gray-800 text-sm">
                     {new Date(log.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                   </span>

                   {/* Feed Interval Display */}
                   {feedInterval && (
                       <span className="flex items-center gap-1 text-[10px] text-gray-500 bg-gray-50 border border-gray-100 px-1.5 py-0.5 rounded-md whitespace-nowrap">
                         <Clock className="w-3 h-3 text-gray-400" />
                         相隔 {feedInterval}
                       </span>
                   )}
                </div>

                <p className="text-gray-600 text-sm whitespace-pre-wrap leading-tight truncate">
                    {getDetails(log)}
                </p>
              </div>

              {/* Delete Button */}
              <button 
                onClick={(e) => {
                    e.stopPropagation();
                    onDeleteLog(log.id);
                }}
                className="p-2 text-gray-300 hover:text-red-400 transition-colors flex-shrink-0"
              >
                <Trash2 className="w-4 h-4" />
              </button>
            </div>
          </div>
        );
      })}

      {sortedLogs.length === 0 && (
        <div className="text-center text-gray-400 py-8 bg-white rounded-xl border border-dashed border-gray-200">
          <p className="text-sm">這一天沒有記錄。</p>
        </div>
      )}
    </div>
  );
};
